#include <ESP8266WiFi.h>
#include <ESP8266HTTPClient.h>
#include <SPIFFS.h>

const char* ssid = "YOUR_WIFI_SSID";
const char* password = "YOUR_WIFI_PASSWORD";
const char* serverName = "YOUR_DEVICE_MANAGEMENT_SERVER";
const char* firmwareUrl = "http://" SERVERNAME "/firmware.bin";

void setup() {
  Serial.begin(115200);
  WiFi.mode(WIFI_STA);
  WiFi.begin(ssid, password);

  while (WiFi.status() != WL_CONNECTED) {
    delay(1000);
    Serial.println("Connecting to WiFi...");
  }
}

void loop() {
  if (WiFi.status() == WL_CONNECTED) {
    HTTPClient http;
    http.begin(firmwareUrl);
    int httpCode = http.GET();

    if (httpCode > 0) {
      File file = SPIFFS.open("/firmware.bin", "w");
      if (!file) {
        Serial.println("Error opening firmware file for writing.");
        return;
      }
      size_t sent = http.getSize();
      size_t received = 0;

      while (received < sent) {
        size_t currentSize = http.readBytes(file, 128);
        if (currentSize == 0) break;
        received += currentSize;
      }

      file.close();
      Serial.printf("Firmware downloaded: %u bytes\n", received);
      ESP.restart();
    } else {
      Serial.printf("Error on HTTP GET request: %d\n", httpCode);
    }

    http.end();
  }
}